(()=>{const t="jon@jonbogaty.com";var e;e=()=>{const e=document.querySelector("[data-copy-email]");e?.addEventListener("click",async()=>{try{await navigator.clipboard.writeText(t),e.textContent="Copied",window.setTimeout(()=>{e.textContent="Copy email"},1600)}catch{window.location.href=`mailto:${t}`}})},"loading"===document.readyState?document.addEventListener("DOMContentLoaded",e,{once:!0}):e()})();